  1→/**
  2→ * Adjusts the chat area width based on user settings (stored as viewport %)
  3→ */
  4→
  5→const STYLE_ID = 'gemini-voyager-chat-width';
  6→const DEFAULT_PERCENT = 70;
  7→const MIN_PERCENT = 30;
  8→const MAX_PERCENT = 100;
  9→const LEGACY_BASELINE_PX = 1200;
 10→
 11→// Selectors based on the export functionality that already works
 12→function getUserSelectors(): string[] {
 13→  return [
 14→    '.user-query-bubble-container',
 15→    '.user-query-container',
 16→    'user-query-content',
 17→    'user-query',
 18→    'div[aria-label="User message"]',
 19→    'article[data-author="user"]',
 20→    '[data-message-author-role="user"]',
 21→  ];
 22→}
 23→
 24→function getAssistantSelectors(): string[] {
 25→  return [
 26→    'model-response',
 27→    '.model-response',
 28→    'response-container',
 29→    '.response-container',
 30→    '.presented-response-container',
 31→    '[aria-label="Gemini response"]',
 32→    '[data-message-author-role="assistant"]',
 33→    '[data-message-author-role="model"]',
 34→    'article[data-author="assistant"]',
 35→  ];
 36→}
 37→
 38→function getTableSelectors(): string[] {
 39→  return [
 40→    'table-block',
 41→    '.table-block',
 42→    'table-block .table-block',
 43→    'table-block .table-content',
 44→    '.table-block.new-table-style',
 45→    '.table-block.has-scrollbar',
 46→    '.table-block .table-content',
 47→  ];
 48→}
 49→
 50→const clampPercent = (value: number, min: number, max: number) =>
 51→  Math.min(max, Math.max(min, Math.round(value)));
 52→
 53→const normalizePercent = (value: number, fallback: number) => {
 54→  if (!Number.isFinite(value)) return fallback;
 55→  if (value > MAX_PERCENT) {
 56→    const approx = (value / LEGACY_BASELINE_PX) * 100;
 57→    return clampPercent(approx, MIN_PERCENT, MAX_PERCENT);
 58→  }
 59→  return clampPercent(value, MIN_PERCENT, MAX_PERCENT);
 60→};
 61→
 62→function applyWidth(widthPercent: number) {
 63→  const normalizedPercent = normalizePercent(widthPercent, DEFAULT_PERCENT);
 64→  // Use screen width as reference to compute pixel-based max-width.
 65→  // This provides adaptive behavior for split-screen / narrow windows:
 66→  // - Fullscreen: width ≈ percent% of screen (as intended by the slider)
 67→  // - Split-screen: content fills available space since pixel max-width > viewport
 68→  const screenWidth = screen.availWidth || screen.width || 1920;
 69→  const widthValue = `${Math.round((normalizedPercent / 100) * screenWidth)}px`;
 70→
 71→  let style = document.getElementById(STYLE_ID) as HTMLStyleElement;
 72→  if (!style) {
 73→    style = document.createElement('style');
 74→    style.id = STYLE_ID;
 75→    document.head.appendChild(style);
 76→  }
 77→
 78→  const userSelectors = getUserSelectors();
 79→  const assistantSelectors = getAssistantSelectors();
 80→  const tableSelectors = getTableSelectors();
 81→
 82→  // Build comprehensive CSS rules
 83→  const userRules = userSelectors.map((sel) => `${sel}`).join(',\n    ');
 84→  const assistantRules = assistantSelectors.map((sel) => `${sel}`).join(',\n    ');
 85→  const tableRules = tableSelectors.map((sel) => `${sel}`).join(',\n    ');
 86→
 87→  // A small gap to account for scrollbars
 88→  const GAP_PX = 10;
 89→
 90→  style.textContent = `
 91→    /* Remove width constraints from outer containers that contain conversations */
