100→    [role="main"]:has(chat-window),
101→    [role="main"]:has(.conversation-container) {
102→      max-width: none !important;
103→    }
104→
105→    /* Target chat window and related containers; A small gap to account for scrollbars */
106→    chat-window,
107→    .chat-container,
108→    chat-window-content,
109→    .chat-history-scroll-container,
110→    .chat-history,
111→    .conversation-container {
112→      max-width: none !important;
113→      padding-right: ${GAP_PX}px !important;
114→      box-sizing: border-box !important;
115→    }
116→
117→    main > div:has(user-query),
118→    main > div:has(model-response),
119→    main > div:has(.conversation-container) {
120→      max-width: none !important;
121→      width: 100% !important;
122→    }
123→
124→    /* Fallback for browsers without :has() support */
125→    @supports not selector(:has(*)) {
