127→      .main-content,
128→      .content-container {
129→        max-width: none !important;
130→      }
131→
132→      main > div:not(:has(button)):not(.main-menu-button) {
133→        max-width: none !important;
134→        width: 100% !important;
135→      }
136→    }
137→
138→    /* User query containers */
139→    ${userRules} {
140→      max-width: ${widthValue} !important;
141→      width: min(100%, ${widthValue}) !important;
142→      margin-left: auto !important;
143→      margin-right: auto !important;
144→    }
145→
146→    /* Model response containers */
147→    ${assistantRules} {
148→      max-width: ${widthValue} !important;
149→      width: min(100%, ${widthValue}) !important;
150→      margin-left: auto !important;
151→      margin-right: auto !important;
