169→    table-block .table-content,
170→    .table-block .table-content {
171→      width: 100% !important;
172→      overflow-x: auto !important;
173→    }
174→
175→    model-response:has(> .deferred-response-indicator),
176→    .response-container:has(img[src*="sparkle"]), 
177→    main > div:has(img[src*="sparkle"]) {
178→      max-width: ${widthValue} !important;
179→      width: min(100%, ${widthValue}) !important;
180→      margin-left: auto !important;
181→      margin-right: auto !important;
182→    }
183→
184→    /* Additional deep targeting for nested elements */
185→    user-query,
186→    user-query > *,
