183→function setupSearchButtonHitTestDebug(): void {
184→  if (searchHitDebugBound) return;
185→  searchHitDebugBound = true;
186→
187→  const onPointerDownCapture = (event: PointerEvent) => {
188→    const searchButton = document.querySelector<HTMLElement>('search-nav-button button');
189→    if (!searchButton) return;
190→
191→    const rect = searchButton.getBoundingClientRect();
192→    if (rect.width <= 0 || rect.height <= 0) return;
193→
194→    const { clientX: x, clientY: y } = event;
195→    const isInSearchRect = x >= rect.left && x <= rect.right && y >= rect.top && y <= rect.bottom;
196→    if (!isInSearchRect) return;
197→
198→    const target = event.target instanceof Element ? event.target : null;
199→    if (target && searchButton.contains(target)) return;
200→
201→    const now = Date.now();
202→    if (now - lastSearchHitDebugAt < SEARCH_HIT_DEBUG_THROTTLE_MS) return;
203→    lastSearchHitDebugAt = now;
204→
205→    const stack = document.elementsFromPoint(x, y).slice(0, 6);
206→    const top = stack[0] ?? null;
207→    const topStyle = top ? window.getComputedStyle(top) : null;
208→
209→    console.warn('[Gemini Voyager][sidebarWidth debug] Search button hit blocked', {
210→      point: { x, y },
211→      target: formatElementForDebug(target),
212→      searchButton: formatElementForDebug(searchButton),
213→      topElement: formatElementForDebug(top),
214→      topElementPointerEvents: topStyle?.pointerEvents ?? null,
215→      topElementZIndex: topStyle?.zIndex ?? null,
216→      stack: stack.map((element) => formatElementForDebug(element)),
217→    });
218→  };
219→
220→  window.addEventListener('pointerdown', onPointerDownCapture, true);
221→  window.addEventListener(
222→    'beforeunload',
223→    () => {
224→      window.removeEventListener('pointerdown', onPointerDownCapture, true);
225→      searchHitDebugBound = false;
226→    },
227→    { once: true },
228→  );
229→}
