233→/** Initialize and start the sidebar width adjuster */
234→export function startSidebarWidthAdjuster(): void {
235→  let currentWidthValue = DEFAULT_PX;
236→  let enabled = false;
237→  setupSearchButtonHitTestDebug();
238→
239→  // 1) Read initial state — request keys without defaults so we can distinguish
240→  // "key never existed" (upgrade) from "explicitly set to false"
241→  try {
242→    chrome.storage?.sync?.get(['geminiSidebarWidth', ENABLED_KEY], (res) => {
243→      const rawW = res?.geminiSidebarWidth;
244→      const w = Number.isFinite(Number(rawW)) ? Number(rawW) : DEFAULT_PX;
245→      const { normalized } = normalizeWidth(w);
246→      currentWidthValue = normalized;
247→
248→      const enabledRaw = res?.[ENABLED_KEY];
249→      if (enabledRaw === undefined) {
250→        // Upgrade path: auto-enable if user had previously customized
251→        const isCustomized =
252→          rawW !== undefined && normalizeWidth(Number(rawW)).normalized !== DEFAULT_PX;
253→        enabled = isCustomized;
254→        if (enabled) {
255→          try {
256→            chrome.storage?.sync?.set({ [ENABLED_KEY]: true });
257→          } catch {}
258→        }
259→      } else {
260→        enabled = enabledRaw === true;
261→      }
262→
263→      if (enabled) {
264→        applyWidth(currentWidthValue);
265→      }
266→
267→      if (Number.isFinite(w) && w !== normalized) {
268→        try {
269→          chrome.storage?.sync?.set({ geminiSidebarWidth: normalized });
270→        } catch (err) {
271→          console.warn('[Gemini Voyager] Failed to migrate sidebar width to %:', err);
272→        }
273→      }
274→    });
275→  } catch (e) {
276→    console.error('[Gemini Voyager] Failed to get sidebar width from storage:', e);
277→  }
278→
279→  // 2) Respond to storage changes (from Popup slider adjustment)
280→  try {
281→    chrome.storage?.onChanged?.addListener((changes, area) => {
282→      if (area !== 'sync') return;
283→
284→      if (changes[ENABLED_KEY]) {
285→        enabled = changes[ENABLED_KEY].newValue === true;
286→        if (enabled) {
287→          applyWidth(currentWidthValue);
288→        } else {
289→          removeStyles();
290→        }
291→      }
292→
293→      if (changes.geminiSidebarWidth) {
294→        const w = Number(changes.geminiSidebarWidth.newValue);
295→        if (Number.isFinite(w)) {
296→          const { normalized } = normalizeWidth(w);
297→          currentWidthValue = normalized;
298→          if (enabled) {
299→            applyWidth(currentWidthValue);
300→          }
301→
302→          if (normalized !== w) {
303→            try {
304→              chrome.storage?.sync?.set({ geminiSidebarWidth: normalized });
305→            } catch (err) {
306→              console.warn('[Gemini Voyager] Failed to migrate sidebar width to % on change:', err);
307→            }
308→          }
309→        }
310→      }
311→    });
312→  } catch (e) {
313→    console.error('[Gemini Voyager] Failed to add storage listener for sidebar width:', e);
314→  }
315→
316→  // // 3) Listen for DOM changes (<bard-sidenav> may be lazily mounted)
317→  // let debounceTimer: number | null = null;
318→  // const observer = new MutationObserver(() => {
319→  //   if (debounceTimer !== null) window.clearTimeout(debounceTimer);
320→  //   debounceTimer = window.setTimeout(() => {
321→  //     applyWidth(currentWidthValue);
322→  //     debounceTimer = null;
323→  //   }, 150);
324→  // });
325→
326→  // const root = document.documentElement || document.body;
327→  // if (root) {
328→  //   observer.observe(root, { childList: true, subtree: true });
329→  // }
330→
331→  // 4) Cleanup
332→  window.addEventListener('beforeunload', () => {
333→    // observer.disconnect();
334→    removeStyles();
335→  });
336→}
