 21→/**
 22→ * Extracts structured content from Gemini's DOM
 23→ * Preserves formatting including LaTeX formulas, code blocks, tables, etc.
 24→ */
 25→
 26→/**
 27→ * querySelector variant that skips elements nested inside model-thoughts / thoughts-container.
 28→ * When the user expands Gemini's "thinking" section, a second `message-content` element
 29→ * appears *before* the real response in DOM order.  A plain `querySelector` would match
 30→ * the thinking panel first, causing exports to grab the wrong content.
 31→ */
 32→function queryOutsideThoughts<T extends Element = Element>(
 33→  root: Element,
 34→  selector: string,
 35→): T | null {
 36→  const candidates = root.querySelectorAll<T>(selector);
 37→  for (const el of Array.from(candidates)) {
 38→    if (!el.closest('model-thoughts, .thoughts-container, .thoughts-content')) {
 39→      return el;
 40→    }
 41→  }
 42→  return null;
 43→}
 44→export class DOMContentExtractor {
 45→  private static DEBUG = false;
 46→  /**
 47→   * Extract user query content
 48→   */
 49→  static extractUserContent(element: HTMLElement): ExtractedContent {
 50→    const result: ExtractedContent = {
 51→      text: '',
 52→      html: '',
 53→      hasImages: false,
 54→      hasFormulas: false,
 55→      hasTables: false,
 56→      hasCode: false,
 57→    };
 58→
 59→    // Check for images
 60→    const images = element.querySelectorAll('user-query-file-preview img, .preview-image');
 61→    result.hasImages = images.length > 0;
 62→
 63→    // Extract text from query-text-line paragraphs
 64→    const textLines = element.querySelectorAll('.query-text-line');
 65→    const textParts: string[] = [];
 66→    textLines.forEach((line) => {
 67→      const el = line as HTMLElement;
 68→      const raw = el.dataset?.userLatexOriginal ?? line.textContent ?? '';
 69→      const text = this.normalizeText(raw);
 70→      if (text) textParts.push(text);
 71→    });
 72→    result.text = textParts.join('\n');
 73→
 74→    // Build HTML representation
 75→    const htmlParts: string[] = [];
 76→
 77→    // Add image markdown
 78→    const imageMarkdown: string[] = [];
 79→    images.forEach((img, index) => {
 80→      const src = (img as HTMLImageElement).src;
 81→      const alt = (img as HTMLImageElement).alt || `Uploaded image ${index + 1}`;
 82→      htmlParts.push(`<img src="${src}" alt="${alt}" />`);
 83→      imageMarkdown.push(`![${alt}](${src})`);
 84→    });
 85→
 86→    // Combine image markdown and text
 87→    const allTextParts: string[] = [];
 88→    if (imageMarkdown.length > 0) {
 89→      allTextParts.push(imageMarkdown.join('\n\n'));
 90→    }
 91→    if (textParts.length > 0) {
 92→      allTextParts.push(textParts.join('\n'));
 93→    }
 94→    result.text = allTextParts.join('\n\n');
 95→
 96→    // Add text paragraphs to HTML
 97→    textParts.forEach((text) => {
 98→      htmlParts.push(`<p>${this.escapeHtml(text)}</p>`);
 99→    });
100→
101→    result.html = htmlParts.join('\n');
102→
103→    return result;
104→  }
105→
106→  /**
107→   * Extract assistant response content with rich formatting
108→   */
109→  static extractAssistantContent(element: HTMLElement): ExtractedContent {
110→    if (this.DEBUG)
111→      console.log('[DOMContentExtractor] extractAssistantContent called, element:', element);
112→
113→    const result: ExtractedContent = {
114→      text: '',
115→      html: '',
116→      hasImages: false,
117→      hasFormulas: false,
118→      hasTables: false,
119→      hasCode: false,
120→    };
121→
122→    // Find message-content first (contains main text and formulas)
