232→const ENABLED_KEY = 'gvChatWidthEnabled';
233→
234→export function startChatWidthAdjuster() {
235→  let currentWidthPercent = DEFAULT_PERCENT;
236→  let enabled = false;
237→
238→  // Load initial state — request keys without defaults so we can distinguish
239→  // "key never existed" (upgrade) from "explicitly set to false"
240→  chrome.storage?.sync?.get(['geminiChatWidth', ENABLED_KEY], (res) => {
241→    const storedWidth = res?.geminiChatWidth;
242→    const numericStoredWidth = typeof storedWidth === 'number' ? storedWidth : DEFAULT_PERCENT;
243→    const normalized = normalizePercent(numericStoredWidth, DEFAULT_PERCENT);
244→    currentWidthPercent = normalized;
245→
246→    const enabledRaw = res?.[ENABLED_KEY];
247→    if (enabledRaw === undefined) {
248→      // Upgrade path: enabled key was never set.
249→      // Auto-enable if user had previously customized the width.
250→      enabled =
251→        typeof storedWidth === 'number' &&
252→        normalizePercent(storedWidth, DEFAULT_PERCENT) !== DEFAULT_PERCENT;
253→      if (enabled) {
254→        try {
255→          chrome.storage?.sync?.set({ [ENABLED_KEY]: true });
256→        } catch {}
257→      }
258→    } else {
259→      enabled = enabledRaw === true;
260→    }
261→
262→    if (enabled) {
263→      applyWidth(currentWidthPercent);
264→    }
265→
266→    if (typeof storedWidth === 'number' && storedWidth !== normalized) {
267→      try {
268→        chrome.storage?.sync?.set({ geminiChatWidth: normalized });
269→      } catch (e) {
270→        console.warn('[Gemini Voyager] Failed to migrate chat width to %:', e);
271→      }
272→    }
273→  });
274→
275→  // Listen for changes from storage
276→  const storageChangeHandler = (
277→    changes: Record<string, chrome.storage.StorageChange>,
278→    area: string,
279→  ) => {
280→    if (area !== 'sync') return;
281→
282→    if (changes[ENABLED_KEY]) {
283→      enabled = changes[ENABLED_KEY].newValue === true;
284→      if (enabled) {
285→        applyWidth(currentWidthPercent);
286→      } else {
287→        removeStyles();
288→      }
289→    }
290→
291→    if (changes.geminiChatWidth) {
292→      const newWidth = changes.geminiChatWidth.newValue;
293→      if (typeof newWidth === 'number') {
294→        const normalized = normalizePercent(newWidth, DEFAULT_PERCENT);
295→        currentWidthPercent = normalized;
296→        if (enabled) {
297→          applyWidth(currentWidthPercent);
298→        }
299→
300→        if (normalized !== newWidth) {
301→          try {
302→            chrome.storage?.sync?.set({ geminiChatWidth: normalized });
303→          } catch (e) {
304→            console.warn('[Gemini Voyager] Failed to migrate chat width to % on change:', e);
305→          }
306→        }
307→      }
308→    }
309→  };
310→
311→  chrome.storage?.onChanged?.addListener(storageChangeHandler);
312→
313→  // Re-apply styles when DOM changes (for dynamic content)
314→  // Use debouncing and cache the width to avoid storage reads
315→  let debounceTimer: number | null = null;
316→  const observer = new MutationObserver(() => {
317→    if (debounceTimer !== null) {
318→      clearTimeout(debounceTimer);
319→    }
320→    debounceTimer = window.setTimeout(() => {
321→      if (enabled) {
322→        applyWidth(currentWidthPercent);
323→      }
324→      debounceTimer = null;
325→    }, 200);
326→  });
327→
328→  // Observe the main conversation area for changes
329→  const main = document.querySelector('main');
330→  if (main) {
331→    observer.observe(main, {
332→      childList: true,
333→      subtree: true,
334→    });
335→  }
336→
337→  // Clean up on unload to prevent memory leaks
338→  window.addEventListener(
339→    'beforeunload',
340→    () => {
341→      observer.disconnect();
342→      removeStyles();
343→      // Remove storage listener
344→      try {
345→        chrome.storage?.onChanged?.removeListener(storageChangeHandler);
346→      } catch (e) {
347→        console.error('[Gemini Voyager] Failed to remove storage listener on unload:', e);
348→      }
349→    },
350→    { once: true },
351→  );
352→}
