// Inspect the table DOM structure
const tables = document.querySelectorAll('table');
const tableBlocks = document.querySelectorAll('table-block, .table-block');
const tableContents = document.querySelectorAll('.table-content');

const result = {
  tables: tables.length,
  tableBlocks: tableBlocks.length,
  tableContents: tableContents.length,
};

// Get the first table's parent hierarchy
if (tables.length > 0) {
  const table = tables[0];
  const parents = [];
  let el = table;
  for (let i = 0; i < 10 && el; i++) {
    const styles = window.getComputedStyle(el);
    parents.push({
      tag: el.tagName.toLowerCase(),
      className: el.className?.toString().substring(0, 100) || '',
      id: el.id || '',
      width: styles.width,
      maxWidth: styles.maxWidth,
      overflowX: styles.overflowX,
      display: styles.display,
      boxSizing: styles.boxSizing,
    });
    el = el.parentElement;
  }
  result.parentChain = parents;

  // Get the actual table dimensions
  const tableRect = table.getBoundingClientRect();
  result.tableRect = { width: tableRect.width, left: tableRect.left, right: tableRect.right };

  // Get the table's own styles
  result.tableStyles = {
    width: window.getComputedStyle(table).width,
    maxWidth: window.getComputedStyle(table).maxWidth,
    tableLayout: window.getComputedStyle(table).tableLayout,
    minWidth: window.getComputedStyle(table).minWidth,
  };
}

JSON.stringify(result, null, 2);

// Check if chatWidth is enabled and what the current style contains
const chatWidthStyle = document.getElementById('gemini-voyager-chat-width');
const result = {
  chatWidthEnabled: !!chatWidthStyle,
  chatWidthContent: chatWidthStyle ? chatWidthStyle.textContent?.substring(0, 500) : 'NOT FOUND',
};

// Also get the model-response container width
const modelResponse = document.querySelector('model-response');
if (modelResponse) {
  const styles = window.getComputedStyle(modelResponse);
  result.modelResponseWidth = styles.width;
  result.modelResponseMaxWidth = styles.maxWidth;
}

// Check viewport and available width
result.viewportWidth = window.innerWidth;
result.screenAvailWidth = screen.availWidth;
result.screenWidth = screen.width;

// Get the full parent chain including outer containers
const tableBlock = document.querySelector('.table-block.has-scrollbar');
