    max-width: 100% !important;
  }
  .table-block-component,
  .horizontal-scroll-wrapper:has(.table-block) {
    max-width: none !important;
  }
`;
document.head.appendChild(cssFix);

// 2. Simulate chatWidth at 90% (as a user might set it)
const screenWidth = screen.availWidth || screen.width || 1920;
const widthValue = `${Math.round((90 / 100) * screenWidth)}px`;
const GAP_PX = 10;

const chatWidth = document.createElement('style');
chatWidth.id = 'gemini-voyager-chat-width';

// Build selectors exactly like the updated code
const userSels = '.user-query-bubble-container,.user-query-container,user-query-content,user-query,div[aria-label="User message"],article[data-author="user"],[data-message-author-role="user"]';
const assistSels = 'model-response,.model-response,response-container,.response-container,.presented-response-container,[aria-label="Gemini response"],[data-message-author-role="assistant"],[data-message-author-role="model"],article[data-author="assistant"]';
// Updated table selectors with NEW entries
const tableSels = 'table-block,.table-block,table-block .table-block,table-block .table-content,.table-block.new-table-style,.table-block.has-scrollbar,.table-block .table-content,.table-block-component,.horizontal-scroll-wrapper';

chatWidth.textContent = `
  .content-wrapper:has(chat-window),.main-content:has(chat-window),.content-container:has(chat-window),.content-container:has(.conversation-container){max-width:none!important}
  [role="main"]:has(chat-window),[role="main"]:has(.conversation-container){max-width:none!important}
  chat-window,.chat-container,chat-window-content,.chat-history-scroll-container,.chat-history,.conversation-container{max-width:none!important;padding-right:${GAP_PX}px!important;box-sizing:border-box!important}
  main>div:has(user-query),main>div:has(model-response),main>div:has(.conversation-container){max-width:none!important;width:100%!important}
  ${userSels}{max-width:${widthValue}!important;width:min(100%,${widthValue})!important;margin-left:auto!important;margin-right:auto!important}
  ${assistSels}{max-width:${widthValue}!important;width:min(100%,${widthValue})!important;margin-left:auto!important;margin-right:auto!important}
  ${tableSels}{max-width:${widthValue}!important;width:min(100%,${widthValue})!important;margin-left:auto!important;margin-right:auto!important;box-sizing:border-box!important}
  table-block .table-block,.table-block.has-scrollbar,.table-block.new-table-style{overflow-x:hidden!important}
  table-block .table-content,.table-block .table-content{width:100%!important;overflow-x:auto!important}
  user-query,user-query>*,user-query>*>*,model-response,model-response>*,model-response>*>*,response-container,response-container>*,response-container>*>*{max-width:${widthValue}!important}
  .presented-response-container,[data-message-author-role]{max-width:${widthValue}!important}
  input-container{max-width:none!important;width:100%!important}
  input-container .input-area-container,input-container input-area-v2{max-width:${widthValue}!important;width:min(100%,${widthValue})!important;margin-left:auto!important;margin-right:auto!important}
  .user-query-bubble-with-background{max-width:${widthValue}!important;width:fit-content!important}
`;
document.head.appendChild(chatWidth);

// Measure final state
const tb = document.querySelector('.table-block.has-scrollbar');
const tc = document.querySelector('.table-content');
const mr = document.querySelector('model-response');
const tbc = document.querySelector('.table-block-component');

JSON.stringify({
  chatWidth: '90%',
  widthValue,
  tableBlock: { w: getComputedStyle(tb).width, mw: getComputedStyle(tb).maxWidth },
  tableContent: { w: getComputedStyle(tc).width, overflow: getComputedStyle(tc).overflowX },
  tableBlockComponent: { w: getComputedStyle(tbc).width },
  modelResponse: { w: getComputedStyle(mr).width },
}, null, 2);

